"use client";

import React from "react";
import { useRouter } from "next/navigation";
import { 
  User, 
  Package, 
  MapPin, 
  Settings, 
  LogOut, 
  ArrowLeft, 
  ChevronRight,
  Heart
} from "lucide-react";
import { useAuth } from "@/lib/AuthProvider";

export default function ProfilePage() {
  const { user, logout } = useAuth();
  const router = useRouter();

  // Se o utilizador não estiver logado, redireciona para o login
  if (!user) {
    if (typeof window !== "undefined") {
      router.push("/auth/login");
    }
    return null;
  }

  const handleLogout = () => {
    logout();
    router.push("/");
  };

  return (
    <div className="min-h-screen bg-[#FDFBF9] font-sans text-black">
      {/* Header da Página de Perfil */}
      <div className="bg-white border-b border-gray-100 sticky top-0 z-10">
        <div className="max-w-4xl mx-auto px-6 py-4 flex items-center justify-between">
          <button 
            onClick={() => router.back()} 
            className="p-2 hover:bg-gray-50 rounded-full transition-colors"
          >
            <ArrowLeft size={20} className="text-gray-600" />
          </button>
          <h1 className="text-sm font-black uppercase tracking-widest text-gray-400">Meu Perfil</h1>
          <button onClick={handleLogout} className="p-2 text-red-400 hover:text-red-600 transition-colors">
            <LogOut size={20} />
          </button>
        </div>
      </div>

      <main className="max-w-4xl mx-auto px-6 py-10">
        {/* Cartão de Identidade */}
        <div className="bg-white rounded-[40px] p-8 shadow-sm border border-gray-50 flex flex-col md:flex-row items-center gap-8 mb-10">
          <div className="w-24 h-24 bg-[#9C7C50] rounded-full flex items-center justify-center text-white text-4xl font-black shadow-lg shadow-[#9C7C50]/20">
            {user.name.charAt(0).toUpperCase()}
          </div>
          <div className="text-center md:text-left flex-1">
            <h2 className="text-3xl font-black text-gray-900">{user.name}</h2>
            <p className="text-gray-400 font-medium">{user.email}</p>
            <div className="flex flex-wrap justify-center md:justify-start gap-2 mt-4">
              <span className="bg-[#9C7C50]/10 text-[#9C7C50] px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-tighter">
                Cliente VIP
              </span>
              <span className="bg-gray-100 text-gray-500 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-tighter">
                Membro desde 2024
              </span>
            </div>
          </div>
          <button className="bg-black text-white px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:scale-105 transition-all">
            Editar Perfil
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {/* Seção de Menu */}
          <div className="space-y-4">
            <h3 className="text-xs font-black uppercase tracking-widest text-gray-400 ml-2">Explorar</h3>
            <MenuButton icon={<Package size={18} />} label="Meus Pedidos" badge="2" />
            <MenuButton icon={<Heart size={18} />} label="Lista de Desejos" />
            <MenuButton icon={<MapPin size={18} />} label="Endereços de Entrega" />
            <MenuButton icon={<Settings size={18} />} label="Privacidade & Segurança" />
          </div>

          {/* Pedidos Recentes Simulados */}
          <div className="space-y-4">
            <h3 className="text-xs font-black uppercase tracking-widest text-gray-400 ml-2">Última Encomenda</h3>
            <div className="bg-white rounded-[32px] p-6 border border-gray-100 shadow-sm">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <p className="text-[10px] font-black text-gray-400 uppercase">Pedido #8821</p>
                  <p className="text-sm font-bold text-gray-800">12 de Janeiro, 2026</p>
                </div>
                <span className="bg-green-100 text-green-600 px-3 py-1 rounded-lg text-[10px] font-black uppercase">
                  Entregue
                </span>
              </div>
              <div className="flex gap-2 mb-4">
                <div className="w-12 h-12 bg-gray-100 rounded-xl"></div>
                <div className="w-12 h-12 bg-gray-100 rounded-xl"></div>
              </div>
              <button className="w-full py-3 bg-gray-50 hover:bg-gray-100 rounded-xl text-[10px] font-black uppercase tracking-widest transition-colors">
                Ver Detalhes
              </button>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}

function MenuButton({ icon, label, badge }: { icon: React.ReactNode, label: string, badge?: string }) {
  return (
    <button className="w-full bg-white p-5 rounded-2xl flex items-center justify-between border border-gray-50 hover:border-[#9C7C50]/30 hover:shadow-md transition-all group">
      <div className="flex items-center gap-4">
        <div className="text-gray-400 group-hover:text-[#9C7C50] transition-colors">{icon}</div>
        <span className="text-sm font-bold text-gray-700">{label}</span>
      </div>
      <div className="flex items-center gap-3">
        {badge && (
          <span className="bg-[#9C7C50] text-white text-[10px] font-bold px-2 py-0.5 rounded-full">
            {badge}
          </span>
        )}
        <ChevronRight size={16} className="text-gray-300" />
      </div>
    </button>
  );
}